={{ JSON.stringify({
  model: "solar-pro3",
  messages: [
    {
      role: "system",
      content: "너는 VeriWay 배리어프리 이동경로 추천 서비스의 입력 분석 AI다. 사용자의 자연어 문장에서 출발지, 목적지, 이동 상태, 피해야 할 요소, 필요한 편의시설을 추출한다. 반드시 JSON만 출력한다. 마크다운 코드블록, 설명 문장, 주석은 절대 출력하지 않는다. 출력 형식은 {"start":"", "destination":"", "mobility_condition":"", "avoid":[], "needs":[], "user_type":"", "missing_info":[], "confidence":""} 이다. 출발지가 없으면 start는 빈 문자열로 두고 missing_info에 "출발지"를 넣는다. 목적지가 없으면 destination은 빈 문자열로 두고 missing_info에 "목적지"를 넣는다.

이동 상태 의미 매핑 규칙은 다음과 같다.

1. 목발, 발목 부상, 다리 부상, 깁스, 무릎 통증, 발 다침, 다리가 아픔과 같은 표현은 mobility_condition을 "목발/부상"으로 분류한다. avoid에는 "계단", "급경사"를 넣는다. needs에는 "엘리베이터", "경사로", "평탄한 보도"를 넣는다.

2. 휠체어 사용자는 mobility_condition을 "휠체어"로 분류한다. avoid에는 "계단", "급경사", "턱"을 넣는다. needs에는 "엘리베이터", "경사로", "평탄한 보도"를 넣는다.

3. 캐리어, 짐 많음, 무거운 짐, 여행가방과 같은 표현은 mobility_condition을 "캐리어/짐"으로 분류한다. avoid에는 "계단"을 넣는다. needs에는 "엘리베이터", "평탄한 보도", "짧은 거리"를 넣는다.

4. 유모차 사용자는 mobility_condition을 "유모차"로 분류한다. avoid에는 "계단", "턱", "급경사"를 넣는다. needs에는 "엘리베이터", "경사로", "평탄한 보도"를 넣는다.

5. 임산부, 노약자, 어르신, 몸이 불편함과 같은 표현은 mobility_condition을 "임산부/노약자"로 분류한다. avoid에는 "계단", "급경사", "긴 이동거리"를 넣는다. needs에는 "엘리베이터", "완만한 경로", "평탄한 보도"를 넣는다.

6. 사용자가 이동 상태를 명확히 말하지 않으면 mobility_condition은 "일반"으로 둔다. 단, 사용자가 계단 없는 길, 편한 길, 엘리베이터 있는 길을 요청하면 avoid와 needs에 해당 조건을 반영한다.

사용자의 표현이 위 단어와 정확히 일치하지 않아도 의미가 유사하면 해당 이동 상태로 분류한다. 예를 들어 "발 다쳤어", "발목 아파", "깁스했어"는 "목발/부상" 유형으로 처리한다. "짐이 많아", "캐리어 끌고 가"는 "캐리어/짐" 유형으로 처리한다.

최종 출력은 반드시 JSON 객체 하나만 출력한다."
    },
    {
      role: "user",
      content: $json.cleaned_input || ""
    }
  ],
  stream: false
}) }}

parameters.jsCode:
const content = $json.choices?.[0]?.message?.content || "";
let parsed;
try { parsed = JSON.parse(content); } catch (e) {
  parsed = { start: "", destination: "", mobility_condition: "", avoid: [], needs: [], user_type: "", missing_info: [], confidence: "low" };
}

const preStart = $("Input_Preprocess").first().json.extracted_start || "";
const preDest  = $("Input_Preprocess").first().json.extracted_destination || "";

if (!parsed.start && preStart)        parsed.start       = preStart;
if (!parsed.destination && preDest)   parsed.destination = preDest;

return [{ json: parsed }];

// n8n 버전에 따라 body가 $json 직접 또는 $json.body 아래에 올 수 있음
const body = $json.body || $json;
const input = body.chatInput || body.message || body.text || "";
const frontStart = body.start || "";
const frontDest  = body.destination || "";
const cleanedInput = input.trim().replace(/\s+/g, " ");
return [{ json: {
  original_input: input,
  cleaned_input: cleanedInput,
  extracted_start: frontStart,
  extracted_destination: frontDest
} }];

// ══════════════════════════════════════════════
//  VeriWay – 구간 기반 Dijkstra 경로 탐색
// ══════════════════════════════════════════════

// ── 건물명 정규화 (별칭 → 정식명) ──────────────
const NAME_ALIAS = {
  '\uB208\uAF43\uAD11\uC7A5\uD648': '\uB208\uAF43\uAD11\uC7A5',
  '\uD504\uB77C\uC774\uAD00':       '\uD504\uB77C\uC784\uAD00',
  '\uC2A4\uD0C0\uBC85\uC2A4':       '\uD504\uB77C\uC784\uAD00',
  '\uB3C4\uC11C\uAD00':             '\uC911\uC559\uB3C4\uC11C\uAD00',
  '\uBBF8\uC220\uB300':             '\uBBF8\uC220\uB300\uD559',
  '\uC74C\uC545\uB300':             '\uC74C\uC545\uB300\uD559',
  '\uC57D\uD559\uB300':             '\uC57D\uD559\uB300\uD559',
  '\uBC31\uC8FC\uB144\uAD00':       '\uBC31\uC8FC\uB144\uAE30\uB150\uAD00',
  '\uCC3D\uD559\uAD00':             '\uBC31\uC8FC\uB144\uAE30\uB150\uAD00',
};
function normName(n) {
  const s = (n || '').trim();
  return NAME_ALIAS[s] || s;
}

const allItems = $input.all();
const segments = allItems.map(item => item.json);

const user      = $('JSON_Parse_Check').first().json;
const userStart = normName(user.start        || '');
const userDest  = normName(user.destination  || '');
const mobility  = (user.mobility_condition || '').toLowerCase();

if (!userStart || !userDest) {
  return [{ json: {
    ...user, has_route: false, best_route: null,
    route_description: '\uCD9C\uBC1C\uC9C0 \uB610\uB294 \uBAA9\uC801\uC9C0\uB97C \uC778\uC2DD\uD558\uC9C0 \uBABB\uD588\uC5B4\uC694.'
  }}];
}
if (userStart === userDest) {
  return [{ json: {
    ...user, has_route: true,
    path: [userStart],
    route_description: userStart,
    best_route: { '\uCD9C\uBC1C\uC9C0': userStart, '\uBAA9\uC801\uC9C0': userDest, '\uACBD\uB85C \uC124\uBA85': userStart, '\uACBD\uB85CID': 'AUTO' }
  }}];
}

// ── 이동 조건 판단 ──────────────────────────
const noStairs   = mobility.includes('\uD720\uCCB4\uC5B4') || mobility.includes('\uBAA9\uBC1C') || mobility.includes('\uBCF4\uC870');
const needsElev  = mobility.includes('\uD720\uCCB4\uC5B4');
const avoidSlope = mobility.includes('\uD720\uCCB4\uC5B4') || mobility.includes('\uBAA9\uBC1C');

// ── 그래프 구성 ──────────────────────────────
const graph = {};
for (const seg of segments) {
  const from = normName(seg['\uCD9C\uBC1C\uC9C0'] || seg['\uCD9C\uBC1C'] || '');
  const to   = normName(seg['\uBAA9\uC801\uC9C0'] || seg['\uB3C4\uCC29'] || '');
  if (!from || !to) continue;

  const hasStairs = (seg['\uACC4\uB2E8'] || '\uC5C6\uC74C') === '\uC788\uC74C' || (seg['\uACC4\uB2E8'] || '') === 'O';
  const hasElev   = (seg['\uC5D8\uB9AC\uBCA0\uC774\uD130'] || 'X')  === '\uC788\uC74C' || (seg['\uC5D8\uB9AC\uBCA0\uC774\uD130'] || '') === 'O';
  const slope     = (seg['\uACBD\uC0AC'] || '\uC5C6\uC74C');
  const guide     = seg['\uC548\uB0B4\uBB38'] || '';

  // 접근성 필터: 계단 있고 엘리베이터도 없으면 건너뜀
  if (noStairs && hasStairs && !hasElev) continue;

  // 가중치
  let w = 1;
  if (slope === '\uAE09\uD568')  w += avoidSlope ? 6 : 1.5;
  if (slope === '\uC644\uB9CC')  w += avoidSlope ? 1.5 : 0.3;
  if (hasStairs && !hasElev) w += noStairs ? 10 : 0.5;
  if (needsElev && !hasElev) w += 2;

  if (!graph[from]) graph[from] = [];
  graph[from].push({ to, w, guide });
}

// ── Dijkstra ─────────────────────────────────
const dist   = { [userStart]: 0 };
const prev   = {};
const gmap   = {};
const vis    = new Set();
const queue  = [{ node: userStart, d: 0 }];

while (queue.length > 0) {
  queue.sort((a, b) => a.d - b.d);
  const { node } = queue.shift();
  if (vis.has(node)) continue;
  vis.add(node);
  if (node === userDest) break;
  if (!graph[node]) continue;

  for (const { to, w, guide } of graph[node]) {
    const nd = (dist[node] || 0) + w;
    if (nd < (dist[to] !== undefined ? dist[to] : Infinity)) {
      dist[to] = nd;
      prev[to]  = node;
      gmap[to]  = guide;
      queue.push({ node: to, d: nd });
    }
  }
}

// ── 경로 복원 ────────────────────────────────
if (!prev[userDest]) {
  return [{ json: {
    ...user, has_route: false, best_route: null,
    route_description: userStart + '\uC5D0\uC11C ' + userDest + '\uAE4C\uC9C0 \uACC4\uB2E8 \uC5C6\uC774 \uAC08 \uC218 \uC788\uB294 \uACBD\uB85C\uAC00 \uC5C6\uC5B4\uC694.'
  }}];
}

const path = [], guides = [];
let cur = userDest;
while (cur) { path.unshift(cur); if (gmap[cur]) guides.unshift(gmap[cur]); cur = prev[cur]; }

const routeDesc = path.join(' \u2192 ');

return [{ json: {
  ...user,
  start: userStart,
  destination: userDest,
  has_route: true,
  path,
  route_description: routeDesc,
  segment_guides: guides,
  best_route: {
    '\uCD9C\uBC1C\uC9C0':   userStart,
    '\uBAA9\uC801\uC9C0':   userDest,
    '\uACBD\uB85C \uC124\uBA85': routeDesc,
    '\uACBD\uB85CID':      'AUTO',
    '\uB0B4\uBD80\uC548\uB0B4':  guides.filter(Boolean).join(' / '),
    '\uC9C0\uB3C4\uC88C\uD45C':  null
  }
}}];
